// Physical sensing components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder mounted on the hoist measuring the crane swing angle"
    DTDFVocab:producedData SwingAngleDataTransmitted
]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer mounted on the platform measuring wind speed impacting the gantry crane"
    DTDFVocab:producedData WindSpeedDataTransmitted
]

instance CartPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder for the cart provided by an Arduino‑based measurement shield"
    DTDFVocab:producedData CartPositionDataTransmitted
]

instance HoistPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder for the hoist provided by an Arduino‑based measurement shield"
    DTDFVocab:producedData HoistPositionDataTransmitted
]

// Physical acting components
instance TMC4671StepMotorController : DTDFVocab:ActingComponent [
    base:desc "TMC4671 Eval motor controller that drives the cart and hoist stepper motors via the Physical Crane Interface"
]

instance PhysicalCraneInterface : DTDFVocab:ActingComponent [
    base:desc "Physical Crane Interface that forwards MQTT control messages to the TMC4671 Eval motor controllers"
]

// Data transmitted instances
instance SwingAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom Anemometer
]

instance CartPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CartPositionEncoder
]

instance HoistPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HoistPositionEncoder
]

// Data instances
instance SwingAngleTelemetry : DTDFVocab:Data [
    base:desc "Time‑series telemetry of crane swing angle recorded at 10 Hz"
    DTDFVocab:inputTo LoggingContainer
    DTDFVocab:fromData SwingAngleDataTransmitted
]

instance WindSpeedTelemetry : DTDFVocab:Data [
    base:desc "Time‑series telemetry of wind speed affecting the crane"
    DTDFVocab:inputTo LoggingContainer
    DTDFVocab:fromData WindSpeedDataTransmitted
]

instance CartPositionTelemetry : DTDFVocab:Data [
    base:desc "Time‑series telemetry of cart horizontal position"
    DTDFVocab:inputTo LoggingContainer
    DTDFVocab:fromData CartPositionDataTransmitted
]

instance HoistPositionTelemetry : DTDFVocab:Data [
    base:desc "Time‑series telemetry of hoist vertical position"
    DTDFVocab:inputTo LoggingContainer
    DTDFVocab:fromData HoistPositionDataTransmitted
]

instance TrajectoryPlanData : DTDFVocab:Data [
    base:desc "Database of pre‑planned optimal trajectories for the gantry crane"
    DTDFVocab:inputTo SimulationContainer
]

instance ValidationMetricsData : DTDFVocab:Data [
    base:desc "Distance metrics between executed and simulated trajectories"
    DTDFVocab:inputTo ValidationContainer
]

instance DashboardSnapshotData : DTDFVocab:Data [
    base:desc "Static snapshots of Grafana dashboards for archival"
    DTDFVocab:inputTo GrafanaContainer
]

// Enabler containers
instance TrajectoryGeneratorContainer : DTDFVocab:Enabler [
    base:desc "Docker container running the Trajectory Generator Service"
    DTDFVocab:enables TrajectoryGeneratorService
]

instance SimulationContainer : DTDFVocab:Enabler [
    base:desc "Docker container running the Simulation Service"
    DTDFVocab:enables SimulationService
]

instance ValidationContainer : DTDFVocab:Enabler [
    base:desc "Docker container running the Continuous Validation Service"
    DTDFVocab:enables ContinuousValidationService
]

instance LoggingContainer : DTDFVocab:Enabler [
    base:desc "Docker container for TimescaleDB that logs telemetry"
    DTDFVocab:enables LoggingService
]

instance GrafanaContainer : DTDFVocab:Enabler [
    base:desc "Docker container running Grafana for visualization"
    DTDFVocab:enables VisualizationService
]

instance MosquittoContainer : DTDFVocab:Enabler [
    base:desc "Docker container running Eclipse Mosquitto MQTT broker"
    DTDFVocab:enables ControlApplicationService, LoggingService
]

instance ControlApplicationEnabler : DTDFVocab:Enabler [
    base:desc "Python Control Application that consumes trajectory commands and publishes control messages via MQTT"
    DTDFVocab:enables ControlApplicationService
]

// Services
instance TrajectoryGeneratorService : DTDFVocab:Service [
    base:desc "Computes swing‑free optimal motion paths using the crane's kinematic model"
    DTDFVocab:provides ForecastedTrajectoryInsight
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Reproduces kinematic behavior for arbitrary trajectories in virtual environment"
    DTDFVocab:provides SimulationResultInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Monitors execution fidelity against simulation and flags deviations in real time"
    DTDFVocab:provides RealTimeDeviationAlertInsight
]

instance LoggingService : DTDFVocab:Service [
    base:desc "Records time‑stamped telemetry into TimescaleDB via MQTT broker"
    DTDFVocab:provides DataPersistedInsight
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Presents real‑time and predicted trajectories with confidence bounds on Grafana dashboards"
    DTDFVocab:provides DashboardChartInsight
]

instance ControlApplicationService : DTDFVocab:Service [
    base:desc "Control application that consumes trajectory commands and publishes control actions via MQTT"
]

// Insights
instance ForecastedTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Forecasted trajectories with confidence bounds derived from trajectory generator"
]

instance SimulationResultInsight : DTDFVocab:Insight [
    base:desc "Simulation outputs illustrating crane kinematics for given trajectories"
]

instance RealTimeDeviationAlertInsight : DTDFVocab:Insight [
    base:desc "Real‑time deviation alerts when executed trajectory diverges from simulated path beyond threshold"
]

instance DataPersistedInsight : DTDFVocab:Insight [
    base:desc "Acknowledgement that telemetry data has been stored into TimescaleDB"
]

instance DashboardChartInsight : DTDFVocab:Insight [
    base:desc "Grafana visualization of current and predicted crane trajectories"
]

// Environment (optional high-level organization)
instance GantryCraneEnvironment : DTDFVocab:Environment [
    base:desc "Lab‑scale gantry crane environment including all sensors and actuators"
    base:contains SwingAngleEncoder, Anemometer, CartPositionEncoder, HoistPositionEncoder, TMC4671StepMotorController, PhysicalCraneInterface
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The twin generates optimal trajectories via the Trajectory Generator Service, publishes them to the MQTT broker, and the Physical Crane Interface consumes them, converting them into servo motor commands for the TMC4671‑Eval controllers. The Continuous Validation Service compares the executed motion to a simulated reference and publishes alerts to the Grafana dashboard when deviation thresholds are exceeded. All command and state updates flow through the same MQTT broker."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Services operate in continuous real‑time; sensor data are sampled and logged at every motion step (~10–20 ms per wheel update), while trajectory computations and validation checks run per commanded trajectory (typically 1–5 s). Exact rates are derived from the motor controller loop frequencies but are not explicitly specified in the documentation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The twin architecture is structured in C4 containers: Database, MQTT broker, Dashboard on the physical side; on the digital side, Logic containers (Control Application, Logging Application, Trajectory Generator Service, Simulation Service, Continuous Validation Service). All are connected via MQTT messaging, the database stores telemetry, and the dashboard exposes real‑time visualization. The Physical Crane Interface acts as bridge between hardware and software."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin models and services cover all lifecycle phases: (a) Designed – CAD models (Autodesk Fusion 360) and kinematic models used during design; (b) Manufactured – Simulation models and control firmware deployed on the physical hardware; (c) Operated – Continuous logging, real‑time control, validation, and visualization during day‑to‑day operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Validation is performed by the Continuous Validation Service, which executes the same trajectory in simulation and measures Euclidean distance between simulated and actual trajectory positions; if the distance exceeds user‑defined thresholds, the system flags a fault. The approach relies on accurate kinematic modelling and synchronous sampling. Uncertainty sources include sensor noise from encoders and anemometer, motor latency, and actuator compliance. The lack of a dedicated physical simulator limits fidelity during development."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between PT and DT occurs over a local Ethernet network using MQTT (port 1883) for command and telemetry messages, and PostgreSQL/TimescaleDB (port 5432) for database storage. MQTT topics are used for trajectory commands, sensor telemetry, and validation alerts. The Physical Crane Interface and all services run on the same host PC, leveraging local TCP/IP."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The twin is deployed on a personal computer that also hosts the physical crane. All services are containerized with Docker; Docker Compose brings up TimescaleDB, Mosquitto, Grafana, and the twin application containers with a single command. The host therefore runs both robotic hardware and the digital twin pipeline in a unified environment."
]
